class Solution {
    public int findTheLongestSubstring(String s) {
        int n = s.length();
        int maxLen = 0;
        int[] count = new int[5];
        Map<Integer, Integer> map = new HashMap<>();
        map.put(0, -1);
        for (int i = 0; i < n; i++) {
            count[getVowelIndex(s.charAt(i))]++;
            count[0] %= 2;
            count[1] %= 2;
            count[2] %= 2;
            count[3] %= 2;
            count[4] %= 2;
            int key = getKey(count);
            if (map.containsKey(key)) {
                maxLen = Math.max(maxLen, i - map.get(key));
            } else {
                map.put(key, i);
            }
        }
        return maxLen;
    }

    private int getVowelIndex(char c) {
        switch (c) {
            case 'a':
                return 0;
            case 'e':
                return 1;
            case 'i':
                return 2;
            case 'o':
                return 3;
            case 'u':
                return 4;
            default:
                return -1;
        }
    }

    private int getKey(int[] count) {
        int key = 0;
        for (int i = 0; i < 5; i++) {
            key = key * 2 + (count[i] % 2);
        }
        return key;
    }
}
